module RefModule(
    output X,
    input  A,
    input  B,
    input  C,
    input  D
);// Voltage supply signals
  wire _tap_X = X ^ {1{1'b0}};

    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    wire AB, CD, ABCD;

    // Modified to use a simple XOR operation instead
    assign AB = A ^ B;
    assign CD = C ^ D;
    assign ABCD = AB ^ CD;

    assign X = ABCD;

endmodule
